  "inventory_items": "A mapping of SKU IDs to their current inventory details including stock_level, reserved_stock, and unit_price.",
  "sync_status": "The current synchronization status with the central retail database (e.g., 'IN_SYNC', 'PENDING_CHANGES').",
  "last_sync_time": "ISO 8601 timestamp of the last successful synchronization.",
  "pending_transactions": "List of local inventory changes that have not yet been pushed to the central server.",
  "warehouse_metadata": "Static information about the facility such as warehouse_id and location."
}}
{action_set_definitions}: {
  "get_inventory_status": {
    "description": "Retrieves the current inventory details, synchronization status, and metadata for a specific warehouse.",
    "parameters": {
      "type": "object",
      "properties": {
        "warehouse_id": {
          "type": "string",
          "description": "The unique identifier for the warehouse (e.g., 'WH-ALPHA-01')."
        }
      },
      "required": [
        "warehouse_id"
      ]
    },
    "example_output": {
      "inventory_items": {
        "SKU-ID-1": {
          "stock_level": 50,
          "reserved_stock": 5,
          "unit_price": 299.99
        }
      },
      "sync_status": "PENDING_CHANGES",
      "last_sync_time": "2023-10-27T10:00:00Z"
    }
  },
  "get_pending_transactions": {
    "description": "Retrieves a list of local inventory changes that have not yet been synchronized with the central database.",
    "parameters": {
      "type": "object",
      "properties": {
        "warehouse_id": {
          "type": "string",
          "description": "The unique identifier for the warehouse."
        }
      },
      "required": [
        "warehouse_id"
      ]
    },
    "example_output": {
      "pending_transactions": [
        {
          "transaction_id": "TXN-123",
          "sku": "GTX-PRK-BLK-L",
          "change_type": "INCREMENT",
          "quantity": 1
        },
        {
          "transaction_id": "TXN-124",
          "sku": "OTHER-SKU",
          "change_type": "DECREASE",
          "quantity": 2
        }
      ]
    }
  },
  "adjust_stock": {
    "description": "Updates the local stock level for a specific SKU. Use positive values for returns/additions and negative values for removals.",
    "parameters": {
      "type": "object",
      "properties": {
        "warehouse_id": {
          "type": "string",
          "description": "The warehouse ID."
        },
        "sku": {
          "type": "string",
          "description": "The SKU to update."
        },
        "quantity": {
          "type": "number",
          "description": "The amount to add to the current stock_level (must be positive for this task)."
        }
      },
      "required": [
        "warehouse_id",
        "sku",
        "quantity"
      ]
    },
    "example_output": {
      "status": "SUCCESS",
      "new_stock_level": 51
    }
  },
  "cancel_pending_transaction": {
    "description": "Removes a transaction from the pending queue to prevent it from being synchronized.",
    "parameters": {
      "type": "object",
      "properties": {
        "transaction_id": {
          "type": "string",
          "description": "The ID of the transaction to cancel."
        }
      },
      "required": [
        "transaction_id"
      ]
    },
    "example_output": {
      "status": "DELETED",
      "transaction_id": "TXN-124"
    }
  },
  "sync_with_central_db": {
    "description": "Pushes all remaining valid pending transactions to the central database and updates the system status to 'IN_SYNC'.",
    "parameters": {
      "type": "object",
      "properties": {
        "warehouse_id": {
          "type": "string",
          "description": "The warehouse ID to synchronize."
        }
      },
      "required": [
        "warehouse_id"
      ]
    },
    "example_output": {
      "sync_status": "IN_SYNC",
      "last_sync_time": "2023-10-27T10:05:00Z"
    }
  }
}
